def _quantize_with_error_threshold(self, colors, method, kmeans, error_threshold):
    low, high = 2, colors
    best_im = None
    while low <= high:
        mid = (low + high) // 2
        candidate = self._quantize(mid, method, kmeans)
        if self._quantize_mse(candidate) <= error_threshold:
            best_im = candidate
            high = mid - 1
        else:
            low = mid + 1

    return best_im if best_im is not None else self._quantize(colors, method, kmeans)

